import "./styles/Login.css";
import { useNavigate } from "react-router-dom";
import { useState } from "react";
import api from "../api/axios";

function Login() {
  const navigate = useNavigate();

  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [role, setRole] = useState("Student");
  const [genre, setGenre] = useState("");
  const [error, setError] = useState("");

  const handleLogin = async () => {
    try {
      setError("");

      // ✅ trim inputs to avoid hidden space bugs
      const data = {
        email: email.trim(),
        password: password.trim(),
        role,
      };

      // send genre ONLY if librarian
      if (role === "Librarian") {
        data.genre = genre.trim();
      }

      const res = await api.post("/auth/login", data);

      const { name, role: userRole, genre: userGenre } = res.data;

      if (userRole === "Student") {
        navigate("/student-dashboard", { state: { name } });
      } else if (userRole === "Librarian") {
        navigate("/librarian-dashboard", { state: { genre: userGenre } });
      } else if (userRole === "Admin") {
        navigate("/admin-dashboard");
      }
    } catch (err) {
      console.log("LOGIN ERROR FROM BACKEND:", err.response?.data);
      setError(err.response?.data?.message || "Login failed");
    }
    localStorage.setItem("isLoggedIn", "true");
  };

  return (
    <div className="login-wrapper">
      <div className="login-card">
        <h2>Login</h2>

        {error && <p className="error">{error}</p>}

        <input
          type="email"
          placeholder="University Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
        />

        <select value={role} onChange={(e) => setRole(e.target.value)}>
          <option>Student</option>
          <option>Librarian</option>
          <option>Admin</option>
        </select>

        {/* Genre only when Librarian */}
        {role === "Librarian" && (
          <input
            type="text"
            placeholder="Genre"
            value={genre}
            onChange={(e) => setGenre(e.target.value)}
          />
        )}

        <button className="login-btn" onClick={handleLogin}>
          Login
        </button>
      </div>
    </div>
  );
}

export default Login;
